// // This module implements a 6-bit parallel load register with an asynchronous reset.
// The register loads the input data on every negative clock edge when the load signal is high.
// The reset signal resets the register to 0 when inactive.
module parallel_load_register
    (
        input rst_n,
        input clk,
        input load,
        input [5:0] data,
        output reg [5:0] q
    );

    always @(posedge clk or negedge rst_n) 
    begin
        if (!rst_n)
            q <= 6'd0;
        else if (load)
            q <= data;
    end

endmodule

